	// Return success response
	return ctx.Status(fiber.StatusOK).JSON(fiber.Map{
		"success": true,
		"message": "Webhook configured successfully",
	})
}

// createSecureHTTPClient creates an HTTP client that prevents SSRF attacks
// by blocking connections to private IP addresses at the network level
func createSecureHTTPClient() *http.Client {
	return &http.Client{
		Timeout: 3 * time.Second,
		Transport: &http.Transport{
			DialContext: func(ctx context.Context, network, addr string) (net.Conn, error) {
				// Split host and port
				host, port, err := net.SplitHostPort(addr)
				if err != nil {
					return nil, err
				}

				// Resolve hostname to IP addresses
				ips, err := net.LookupIP(host)
				if err != nil {
					return nil, err
				}

				// Try to connect to the first non-private IP
				var dialer net.Dialer
				dialer.Timeout = 3 * time.Second

				for _, ip := range ips {
					if isPrivateIP(ip) {
						continue
					}

					conn, err := dialer.DialContext(ctx, network, net.JoinHostPort(ip.String(), port))
					if err == nil {
						return conn, nil
					}
				}

				return nil, errors.New("no public IP available")
			},
		},
		CheckRedirect: func(req *http.Request, via []*http.Request) error {
			// Prevent redirects to avoid SSRF via redirect
			return http.ErrUseLastResponse
		},
	}
}

// isPrivateIP checks if an IP address is private/internal
func isPrivateIP(ip net.IP) bool {
	// Normalize to 16-byte representation
	ip = ip.To16()
	if ip == nil {
		return true
	}

	// Check for loopback addresses (127.0.0.0/8, ::1)
	if ip.IsLoopback() {
		return true
	}

	// IPv4 specific checks
	if ip4 := ip.To4(); ip4 != nil {
		// 10.0.0.0/8
		if ip4[0] == 10 {
			return true
		}
		// 172.16.0.0/12
		if ip4[0] == 172 && ip4[1] >= 16 && ip4[1] <= 31 {
			return true
		}
		// 192.168.0.0/16
		if ip4[0] == 192 && ip4[1] == 168 {
			return true
		}
		// 169.254.0.0/16 (link-local)
		if ip4[0] == 169 && ip4[1] == 254 {
			return true
		}
		// 0.0.0.0/8
		if ip4[0] == 0 {
			return true
		}
		// 224.0.0.0/4 (multicast)
		if ip4[0] >= 224 && ip4[0] <= 239 {
			return true
		}
	} else {
		// IPv6 checks
		// fc00::/7 (unique local addresses)
		if ip[0]&0xfe == 0xfc {
			return true
		}
		// fe80::/10 (link-local)
		if ip[0] == 0xfe && (ip[1]&0xc0) == 0x80 {
			return true
		}
		// ff00::/8 (multicast)
		if ip[0] == 0xff {
			return true
		}
	}

	return false
}

