package main

import (
	"net/http"
	"sync"
	"time"

	"github.com/gofiber/fiber/v2"
)

// Request body structure
type ConfigureWebhookRequest struct {
	WebhookURL string `json:"webhook_url"`
}

// Response structure
type ConfigureWebhookResponse struct {
	Success bool   `json:"success"`
	Message string `json:"message"`
}

// In-memory storage for webhook configuration
var (
	webhookURL  string
	configMutex sync.RWMutex
)

func ConfigureWebhook(ctx *fiber.Ctx) error {
	var req ConfigureWebhookRequest

	// Parse JSON body
	if err := ctx.BodyParser(&req); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(ConfigureWebhookResponse{
			Success: false,
			Message: "Invalid JSON body: " + err.Error(),
		})
	}

	// Validate webhook_url field
	if req.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(ConfigureWebhookResponse{
			Success: false,
			Message: "webhook_url is required",
		})
	}

	// Create HTTP client with 3-second timeout
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Send GET request to validate the webhook URL
	resp, err := client.Get(req.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(ConfigureWebhookResponse{
			Success: false,
			Message: "Failed to validate webhook URL: " + err.Error(),
		})
	}
	defer resp.Body.Close()

	// Check if webhook returns successful status code (2xx)
	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return ctx.Status(fiber.StatusBadRequest).JSON(ConfigureWebhookResponse{
			Success: false,
			Message: "Webhook URL returned non-success status: " + resp.Status,
		})
	}

	// Save the configuration (thread-safe)
	configMutex.Lock()
	webhookURL = req.WebhookURL
	configMutex.Unlock()

	// Return success response
	return ctx.Status(fiber.StatusOK).JSON(ConfigureWebhookResponse{
		Success: true,
		Message: "Webhook configured successfully",
	})
}

func main() {
	app := fiber.New()

	// Register the handler
	app.Post("/configure-webhook", ConfigureWebhook)

	// Start server
	app.Listen(":3000")
}

