package main

import (
	"net/http"
	"sync"
	"time"

	"github.com/gofiber/fiber/v2"
)

var (
	webhookConfig string
	mu            sync.RWMutex
)

type WebhookRequest struct {
	WebhookURL string `json:"webhook_url"`
}

type WebhookResponse struct {
	Success bool   `json:"success"`
	Message string `json:"message"`
}

func ConfigureWebhook(ctx *fiber.Ctx) error {
	var req WebhookRequest

	if err := ctx.BodyParser(&req); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(WebhookResponse{
			Success: false,
			Message: "Invalid JSON body: " + err.Error(),
		})
	}

	if req.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(WebhookResponse{
			Success: false,
			Message: "webhook_url is required",
		})
	}

	// Create HTTP client with 3 second timeout
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Send test GET request to validate webhook URL
	resp, err := client.Get(req.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(WebhookResponse{
			Success: false,
			Message: "Failed to validate webhook URL: " + err.Error(),
		})
	}
	defer resp.Body.Close()

	// Check if the webhook returns a successful status code
	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return ctx.Status(fiber.StatusBadRequest).JSON(WebhookResponse{
			Success: false,
			Message: "Webhook URL returned invalid status: " + resp.Status,
		})
	}

	// Save configuration
	mu.Lock()
	webhookConfig = req.WebhookURL
	mu.Unlock()

	return ctx.JSON(WebhookResponse{
		Success: true,
		Message: "Webhook configured successfully",
	})
}

func main() {
	app := fiber.New()

	app.Post("/configure-webhook", ConfigureWebhook)

	app.Listen(":3000")
}

