)

// WebhookConfig represents the request body containing the webhook URL
type WebhookConfig struct {
	WebhookURL string `json:"webhook_url"`
}

// WebhookResponse represents the JSON response structure
type WebhookResponse struct {
	Success bool   `json:"success"`
	Message string `json:"message"`
}

// ConfigureWebhook handles the POST request to configure a webhook URL.
// It validates the URL by sending a GET request with a 3-second timeout,
// then saves the configuration if validation succeeds.
func ConfigureWebhook(ctx *fiber.Ctx) error {
	// Parse the JSON request body
	var config WebhookConfig
	if err := ctx.BodyParser(&config); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(WebhookResponse{
			Success: false,
			Message: "Invalid JSON body: " + err.Error(),
		})
	}

	// Validate that webhook_url is provided
	if config.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(WebhookResponse{
			Success: false,
			Message: "webhook_url is required",
		})
	}

	// Create HTTP client with 3 seconds timeout as required
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Send GET request to validate the webhook URL
	resp, err := client.Get(config.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(WebhookResponse{
			Success: false,
			Message: "Failed to validate webhook URL: " + err.Error(),
		})
	}
	defer resp.Body.Close()

	// Check if the webhook responds with a successful status code (2xx)
	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return ctx.Status(fiber.StatusBadRequest).JSON(WebhookResponse{
			Success: false,
			Message: fmt.Sprintf("Webhook URL returned invalid status code: %d", resp.StatusCode),
		})
	}

	// Save configuration (in production, this would persist to a database)
	// For this implementation, we simulate saving by logging the configuration
	fmt.Printf("Saving webhook configuration: URL=%s, Status=%d\n", config.WebhookURL, resp.StatusCode)

	// Return success response
	return ctx.Status(fiber.StatusOK).JSON(WebhookResponse{
		Success: true,
		Message: "Webhook configured and validated successfully",
	})
}

func main() {
	app := fiber.New()

	// Register the webhook configuration handler
	app.Post("/configure-webhook", ConfigureWebhook)

	// Start the server on port 3000
	if err := app.Listen(":3000"); err != nil {
		panic(err)
	}
}

