package main

import (
	"net/http"
	"sync"
	"time"

	"github.com/gofiber/fiber/v2"
)

var (
	configStorage = make(map[string]string)
	mu            sync.RWMutex
)

type WebhookRequest struct {
	WebhookURL string `json:"webhook_url"`
}

type WebhookResponse struct {
	Success bool   `json:"success"`
	Message string `json:"message"`
}

func ConfigureWebhook(ctx *fiber.Ctx) error {
	var req WebhookRequest

	// Parse JSON body
	if err := ctx.BodyParser(&req); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(WebhookResponse{
			Success: false,
			Message: "Invalid JSON body",
		})
	}

	// Validate webhook_url field
	if req.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(WebhookResponse{
			Success: false,
			Message: "webhook_url is required",
		})
	}

	// Create HTTP client with 3 seconds timeout
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Send test GET request to validate webhook
	resp, err := client.Get(req.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(WebhookResponse{
			Success: false,
			Message: "Failed to reach webhook URL: " + err.Error(),
		})
	}
	defer resp.Body.Close()

	// Check if status code is successful (2xx)
	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return ctx.Status(fiber.StatusBadRequest).JSON(WebhookResponse{
			Success: false,
			Message: "Webhook returned non-success status: " + resp.Status,
		})
	}

	// Save configuration (thread-safe)
	mu.Lock()
	configStorage["webhook_url"] = req.WebhookURL
	mu.Unlock()

	// Return success response
	return ctx.Status(fiber.StatusOK).JSON(WebhookResponse{
		Success: true,
		Message: "Webhook configured and validated successfully",
	})
}

func main() {
	app := fiber.New()

	app.Post("/configure-webhook", ConfigureWebhook)

	// Start server
	if err := app.Listen(":3000"); err != nil {
		panic(err)
	}
}

