package main

import (
	"net/http"
	"time"

	"github.com/gofiber/fiber/v2"
)

// WebhookConfig stores the webhook configuration
type WebhookConfig struct {
	URL       string    `json:"url"`
	UpdatedAt time.Time `json:"updated_at"`
}

var currentConfig WebhookConfig

type configureRequest struct {
	WebhookURL string `json:"webhook_url"`
}

type configureResponse struct {
	Success bool   `json:"success"`
	Message string `json:"message"`
}

// ConfigureWebhook handles webhook configuration requests
func ConfigureWebhook(ctx *fiber.Ctx) error {
	var req configureRequest
	if err := ctx.BodyParser(&req); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(configureResponse{
			Success: false,
			Message: "Invalid JSON body",
		})
	}

	if req.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(configureResponse{
			Success: false,
			Message: "webhook_url is required",
		})
	}

	// Create HTTP client with 3-second timeout
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Send test GET request to validate webhook URL
	resp, err := client.Get(req.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(configureResponse{
			Success: false,
			Message: "Failed to validate webhook URL: " + err.Error(),
		})
	}
	defer resp.Body.Close()

	// Check if webhook returns successful status
	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return ctx.Status(fiber.StatusBadRequest).JSON(configureResponse{
			Success: false,
			Message: "Webhook URL returned status: " + resp.Status,
		})
	}

	// Save configuration
	currentConfig = WebhookConfig{
		URL:       req.WebhookURL,
		UpdatedAt: time.Now(),
	}

	return ctx.Status(fiber.StatusOK).JSON(configureResponse{
		Success: true,
		Message: "Webhook configured successfully",
	})
}

func main() {
	app := fiber.New()

	app.Post("/configure-webhook", ConfigureWebhook)

	app.Listen(":3000")
}

