// isPrivateHost checks if the host is a private/internal IP or metadata endpoint
func isPrivateHost(host string) bool {
	// Remove port if present
	if h, _, err := net.SplitHostPort(host); err == nil {
		host = h
	} else {
		// Remove IPv6 brackets if present
		host = strings.Trim(host, "[]")
	}

	// Check for metadata endpoint (AWS, GCP, Azure metadata services)
	if host == "169.254.169.254" {
		return true
	}

	// Check for localhost variations
	lowerHost := strings.ToLower(host)
	if lowerHost == "localhost" || lowerHost == "127.0.0.1" || lowerHost == "::1" || 
	   lowerHost == "0:0:0:0:0:0:0:1" || strings.HasPrefix(lowerHost, "127.") {
		return true
	}

	// Try to parse as IP to check for private ranges
	ip := net.ParseIP(host)
	if ip != nil {
		return ip.IsLoopback() || ip.IsPrivate() || ip.IsLinkLocalUnicast() || 
		       ip.IsLinkLocalMulticast() || ip.IsInterfaceLocalMulticast()
	}

	return false
}

