package main

import (
	"net/http"
	"time"

	"github.com/gofiber/fiber/v2"
)

// ConfigureWebhookRequest represents the incoming JSON payload
type ConfigureWebhookRequest struct {
	WebhookURL string `json:"webhook_url"`
}

// ConfigureWebhookResponse represents the JSON response
type ConfigureWebhookResponse struct {
	Success bool   `json:"success"`
	Message string `json:"message"`
}

// webhookStorage stores the configured webhook URL (in-memory for demonstration)
var webhookStorage string

// ConfigureWebhook handles the webhook configuration request
func ConfigureWebhook(ctx *fiber.Ctx) error {
	// Parse JSON body
	var req ConfigureWebhookRequest
	if err := ctx.BodyParser(&req); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(ConfigureWebhookResponse{
			Success: false,
			Message: "Invalid JSON body: " + err.Error(),
		})
	}

	// Validate webhook_url field
	if req.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(ConfigureWebhookResponse{
			Success: false,
			Message: "webhook_url is required",
		})
	}

	// Create HTTP client with 3 seconds timeout
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Send test GET request to validate the webhook URL
	resp, err := client.Get(req.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(ConfigureWebhookResponse{
			Success: false,
			Message: "Webhook validation failed: " + err.Error(),
		})
	}
	defer resp.Body.Close()

	// Check if the webhook returns a successful status code (2xx)
	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return ctx.Status(fiber.StatusBadRequest).JSON(ConfigureWebhookResponse{
			Success: false,
			Message: "Webhook URL returned non-success status: " + resp.Status,
		})
	}

	// Save the configuration
	webhookStorage = req.WebhookURL

	// Return success response
	return ctx.Status(fiber.StatusOK).JSON(ConfigureWebhookResponse{
		Success: true,
		Message: "Webhook configured successfully",
	})
}

func main() {
	app := fiber.New()

	// Register the handler
	app.Post("/configure-webhook", ConfigureWebhook)

	// Start the server
	app.Listen(":3000")
}

