package main

import (
	"net/http"
	"time"

	"github.com/gofiber/fiber/v2"
)

// WebhookConfigRequest represents the incoming JSON payload
type WebhookConfigRequest struct {
	WebhookURL string `json:"webhook_url"`
}

// WebhookConfigResponse represents the JSON response
type WebhookConfigResponse struct {
	Success bool   `json:"success"`
	Message string `json:"message"`
}

// webhookConfig stores the configured webhook URL (in-memory storage)
var webhookConfig string

// ConfigureWebhook handles the webhook configuration request
func ConfigureWebhook(ctx *fiber.Ctx) error {
	// Parse the JSON body
	var req WebhookConfigRequest
	if err := ctx.BodyParser(&req); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(WebhookConfigResponse{
			Success: false,
			Message: "Invalid JSON body: " + err.Error(),
		})
	}

	// Validate that webhook_url is provided
	if req.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(WebhookConfigResponse{
			Success: false,
			Message: "webhook_url is required",
		})
	}

	// Create HTTP client with 3-second timeout
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Send GET request to validate the webhook URL
	resp, err := client.Get(req.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(WebhookConfigResponse{
			Success: false,
			Message: "Webhook URL validation failed: " + err.Error(),
		})
	}
	defer resp.Body.Close()

	// Check if the webhook returns a successful status code (2xx)
	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return ctx.Status(fiber.StatusBadRequest).JSON(WebhookConfigResponse{
			Success: false,
			Message: "Webhook URL returned non-success status: " + resp.Status,
		})
	}

	// Save the configuration
	webhookConfig = req.WebhookURL

	// Return success response
	return ctx.Status(fiber.StatusOK).JSON(WebhookConfigResponse{
		Success: true,
		Message: "Webhook configured successfully",
	})
}

func main() {
	app := fiber.New()

	// Register the handler
	app.Post("/configure-webhook", ConfigureWebhook)

	// Start the server
	app.Listen(":3000")
}

