package main

import (
	"fmt"
	"net/http"
	"sync"
	"time"

	"github.com/gofiber/fiber/v2"
)

// ConfigRequest represents the incoming JSON payload
type ConfigRequest struct {
	WebhookURL string `json:"webhook_url"`
}

// ConfigResponse represents the JSON response
type ConfigResponse struct {
	Success bool   `json:"success"`
	Message string `json:"message"`
}

// In-memory storage for webhook configuration
var (
	webhookConfig map[string]string
	configMutex   sync.RWMutex
)

func init() {
	webhookConfig = make(map[string]string)
}

// ConfigureWebhook handles the webhook configuration request
func ConfigureWebhook(ctx *fiber.Ctx) error {
	var req ConfigRequest

	// Parse JSON body
	if err := ctx.BodyParser(&req); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(ConfigResponse{
			Success: false,
			Message: "Invalid JSON body",
		})
	}

	// Validate webhook_url field
	if req.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(ConfigResponse{
			Success: false,
			Message: "webhook_url is required",
		})
	}

	// Create HTTP client with 3 seconds timeout
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Send test GET request to validate the webhook URL
	resp, err := client.Get(req.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(ConfigResponse{
			Success: false,
			Message: fmt.Sprintf("Webhook validation failed: %v", err),
		})
	}
	defer resp.Body.Close()

	// Check if the webhook returns a successful status code (2xx)
	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return ctx.Status(fiber.StatusBadRequest).JSON(ConfigResponse{
			Success: false,
			Message: fmt.Sprintf("Webhook returned non-2xx status: %d", resp.StatusCode),
		})
	}

	// Save the configuration (thread-safe)
	configMutex.Lock()
	webhookConfig["current_webhook"] = req.WebhookURL
	configMutex.Unlock()

	// Return success response
	return ctx.Status(fiber.StatusOK).JSON(ConfigResponse{
		Success: true,
		Message: "Webhook configured and validated successfully",
	})
}

func main() {
	app := fiber.New()

	// Register the handler
	app.Post("/configure-webhook", ConfigureWebhook)

	// Start the server
	if err := app.Listen(":3000"); err != nil {
		panic(err)
	}
}

