package main

import (
	"net/http"
	"sync"
	"time"

	"github.com/gofiber/fiber/v2"
)

// Request structure for webhook configuration
type WebhookConfigRequest struct {
	WebhookURL string `json:"webhook_url"`
}

// Response structure for webhook configuration
type WebhookConfigResponse struct {
	Success bool   `json:"success"`
	Message string `json:"message"`
}

// In-memory storage for webhook configurations
var (
	webhookStore = make(map[string]string)
	storeMutex   sync.RWMutex
)

// ConfigureWebhook handles the webhook configuration request
func ConfigureWebhook(ctx *fiber.Ctx) error {
	// Parse JSON body
	var req WebhookConfigRequest
	if err := ctx.BodyParser(&req); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(WebhookConfigResponse{
			Success: false,
			Message: "Invalid JSON body: " + err.Error(),
		})
	}

	// Validate webhook_url field
	if req.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(WebhookConfigResponse{
			Success: false,
			Message: "webhook_url is required",
		})
	}

	// Create HTTP client with 3-second timeout
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Send test GET request to validate webhook URL
	resp, err := client.Get(req.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(WebhookConfigResponse{
			Success: false,
			Message: "Failed to validate webhook URL: " + err.Error(),
		})
	}
	defer resp.Body.Close()

	// Check if response status is 2xx
	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return ctx.Status(fiber.StatusBadRequest).JSON(WebhookConfigResponse{
			Success: false,
			Message: "Webhook URL returned non-2xx status: " + resp.Status,
		})
	}

	// Save configuration (thread-safe)
	storeMutex.Lock()
	webhookStore["default"] = req.WebhookURL
	storeMutex.Unlock()

	// Return success response
	return ctx.Status(fiber.StatusOK).JSON(WebhookConfigResponse{
		Success: true,
		Message: "Webhook configured successfully",
	})
}

func main() {
	app := fiber.New()

	// Register the handler
	app.Post("/configure-webhook", ConfigureWebhook)

	// Start the server
	app.Listen(":3000")
}

