	client := &http.Client{
		Timeout: 5 * time.Second,
		Transport: &http.Transport{
			DialContext: func(ctx context.Context, network, addr string) (net.Conn, error) {
				// Split host and port
				host, port, err := net.SplitHostPort(addr)
				if err != nil {
					return nil, err
				}

				// Resolve the hostname to IP addresses
				ips, err := net.LookupIP(host)
				if err != nil {
					return nil, err
				}

				// Attempt to connect to the first non-private IP
				var dialer net.Dialer
				for _, ip := range ips {
					if isPrivateIP(ip) {
						continue
					}
					return dialer.DialContext(ctx, network, net.JoinHostPort(ip.String(), port))
				}

				return nil, fmt.Errorf("no valid public IP found for host")
			},
		},
		// Prevent redirects to avoid SSRF bypass via redirect to internal addresses
		CheckRedirect: func(req *http.Request, via []*http.Request) error {
			return http.ErrUseLastResponse
		},
	}

	// Create a context with timeout for the request
	reqCtx, cancel := context.WithTimeout(context.Background(), 5*time.Second)
	defer cancel()

	// Send GET request to webhook URL (as per requirements)
	httpReq, err := http.NewRequestWithContext(reqCtx, http.MethodGet, req.WebhookURL, nil)
	if err != nil {
		return ctx.Status(fiber.StatusInternalServerError).JSON(fiber.Map{
			"success": false,
			"error":   "Failed to create test request",
		})
	}

	// Set headers to identify this as a test request
	httpReq.Header.Set("User-Agent", "Webhook-Validator/1.0")
	httpReq.Header.Set("Accept", "application/json, text/plain, */*")

	resp, err := client.Do(httpReq)
	if err != nil {
		// Sanitize error message to prevent information leakage about internal network
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Failed to connect to webhook URL",
		})
	}
	defer resp.Body.Close()

	// Check if the webhook responded successfully (2xx status)
	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Webhook URL returned non-success status",
		})
	}

